const { execSync } = require('child_process');
const data = $input.item.json;
const val = (data.query && data.query.app_name) ? data.query.app_name : data.app_name;
if (!val) { return [{ json: { stdout: '', stderr: 'No app_name provided. Got: ' + JSON.stringify(data) } }]; }
try {
  const cmd = 'argocd app rollback ' + val + ' --server host.docker.internal:8080 --insecure';
  const stdout = execSync(cmd, { encoding: 'utf8', timeout: 30000 });
  return [{ json: { stdout: stdout || 'Done.', stderr: '' } }];
} catch(e) {
  return [{ json: { stdout: e.stdout || '', stderr: e.stderr || e.message } }];
}
